let prijsData = global.get('ZonneplanTijdsloten');
let cheapHours = global.get('ZonneplanCheapHours');
let expensiveHours = global.get('ZonneplanExpensiveHours');
let cheapAvg = Number(global.get('ZonneplanCheapAvg') || 0);

cheapHours = Array.isArray(cheapHours) ? cheapHours : [];
expensiveHours = Array.isArray(expensiveHours) ? expensiveHours : [];

let soc = Number(global.get('BatterySOC') || 0);
let pvSurplus = Number(global.get('PVSurplusW') || 0);

let hour = new Date().getHours();

if (!prijsData || !prijsData.data || !prijsData.data[hour]) {
    node.status({ fill: 'red', shape: 'ring', text: 'missing current hour price' });
    return null;
}

let priceNow = Number(prijsData.data[hour].prijsZP);

const socMin = 30;
const socFull = 90;
const pvMin = 500;
const dimThreshold = -0.01;
const minSpread = 0.08;
const pvSurplusMaxForDischarge = 200;

let charge = 0;
let discharge = 0;
let dim = 0;
let mode = 'SELF';

// PRIORITEIT 1: dimmen als laatste redmiddel bij volle batterij + negatieve prijs
if (soc >= socFull && pvSurplus >= pvMin && priceNow <= dimThreshold) {
    dim = 1;
    mode = 'DIM';
}
// PRIORITEIT 2: laden op goedkope uren zolang batterij nog niet vol is
else if (cheapHours.includes(hour) && soc < socFull) {
    charge = 1;
    mode = 'CHARGE';
}
// PRIORITEIT 3: ontladen alleen op geselecteerd duur uur, met genoeg spread en weinig PV-overschot
else if (
    expensiveHours.includes(hour) &&
    soc > socMin &&
    pvSurplus < pvSurplusMaxForDischarge &&
    priceNow >= (cheapAvg + minSpread)
) {
    discharge = 1;
    mode = 'DISCHARGE';
}

msg.payload = {
    mode: mode,
    charge: charge,
    discharge: discharge,
    dim: dim,
    hour: hour,
    priceNow: priceNow,
    soc: soc,
    pvSurplus: pvSurplus,
    cheapAvg: cheapAvg,
    cheapHours: cheapHours,
    expensiveHours: expensiveHours
};

node.status({
    fill: mode === 'CHARGE' ? 'green' :
          mode === 'DISCHARGE' ? 'yellow' :
          mode === 'DIM' ? 'red' : 'grey',
    shape: 'dot',
    text: mode + ' h=' + hour + ' p=' + priceNow + ' soc=' + soc
});

return [
    { payload: charge, topic: 'charge' },
    { payload: discharge, topic: 'discharge' },
    { payload: dim, topic: 'dim' },
    { payload: msg.payload, topic: 'mode' }
];

