// Marstek Force Mode sequence
// payload: 0=None, 1=Charge, 2=Discharge
// Bij Charge/Discharge blijft RS485 enabled
// Bij None stopt force mode en disablet RS485

const mode = Number(msg.payload);

const max = Number(global.get("setMax") ?? 90);
const min = Number(global.get("setMin") ?? 30);

const ENABLE = 21930;
const DISABLE = 21947;

const delayMode = 900;
const delayTarget = 1500;
const delayDisable = 2500;

if (![0, 1, 2].includes(mode)) {
    node.status({
        fill: "red",
        shape: "ring",
        text: `unknown mode ${mode}`
    });
    return [null, null, null, {
        payload: `unknown mode ${mode}`,
        topic: "error"
    }];
}

// ---------- NONE / STOP ----------
if (mode === 0) {

    node.status({
        fill: "grey",
        shape: "ring",
        text: "None: stop & disable"
    });

    // enable eerst
    node.send([
        { payload: ENABLE, topic: "rs485-enable" },
        null,
        null,
        { payload: "enable before none", topic: "debug" }
    ]);

    // force mode none
    setTimeout(() => {
        node.send([
            null,
            { payload: 0, topic: "force-none" },
            null,
            { payload: "force mode none", topic: "debug" }
        ]);
    }, delayMode);

    // disable daarna
    setTimeout(() => {
        node.send([
            { payload: DISABLE, topic: "rs485-disable" },
            null,
            null,
            { payload: "rs485 disabled", topic: "debug" }
        ]);
    }, delayDisable);

    return null;
}

// ---------- CHARGE / DISCHARGE ----------
const target = mode === 1 ? max : min;
const label = mode === 1 ? "Charge" : "Discharge";

node.status({
    fill: mode === 1 ? "green" : "yellow",
    shape: "dot",
    text: `${label} target ${target}% keep enabled`
});

// enable, blijft actief
node.send([
    { payload: ENABLE, topic: "rs485-enable-keep" },
    null,
    null,
    { payload: `${label}: enable`, topic: "debug" }
]);

// force mode
setTimeout(() => {
    node.send([
        null,
        { payload: mode, topic: "force-mode" },
        null,
        { payload: `${label}: mode ${mode}`, topic: "debug" }
    ]);
}, delayMode);

// target SOC
setTimeout(() => {
    node.send([
        null,
        null,
        { payload: target, topic: "target-soc" },
        { payload: `${label}: target ${target}%`, topic: "debug" }
    ]);
}, delayTarget);

return null;

